from prometheus_client import Counter, Histogram, Gauge, CollectorRegistry, generate_latest
from prometheus_client.core import GaugeMetricFamily, CounterMetricFamily, REGISTRY
from collections import defaultdict
from threading import Lock
import re

class CardinalityLimitedMetrics:
    def __init__(self, max_unique_combinations=1000, max_paths=500, max_users=500):
        self.max_unique_combinations = max_unique_combinations
        self.max_paths = max_paths
        self.max_users = max_users
        
        self.lock = Lock()
        
        self.user_path_combinations = {}
        self.user_hashes = {}
        self.path_patterns = {}
        
        self.total_requests = Counter(
            'http_requests_total',
            'Total HTTP requests',
            ['status']
        )
        
        self.request_duration = Histogram(
            'http_request_duration_seconds',
            'HTTP request duration',
            ['status']
        )
        
        self.active_sessions = Gauge(
            'http_active_sessions',
            'Number of active sessions'
        )
        
        self.session_tracker = {}
        self.session_last_seen = {}
        
        self.cardinality_limit_hits = Counter(
            'metrics_cardinality_limit_hits_total',
            'Number of times cardinality limit was hit',
            ['limit_type']
        )
        
        self.unique_combinations_gauge = Gauge(
            'metrics_unique_combinations',
            'Current number of unique user-path combinations tracked'
        )
        
    def _hash_user_id(self, user_id):
        if user_id not in self.user_hashes:
            hash_obj = hashlib.sha256(str(user_id).encode())
            self.user_hashes[user_id] = hash_obj.hexdigest()[:16]
        return self.user_hashes[user_id]
    
    def _normalize_path(self, path):
        path = re.sub(r'/\d+', '/{id}', path)
        path = re.sub(r'/[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}', '/{uuid}', path, flags=re.IGNORECASE)
        path = re.sub(r'/[0-9a-f]{24}', '/{objectid}', path, flags=re.IGNORECASE)
        path = re.sub(r'/[0-9a-f]{32}', '/{hash}', path, flags=re.IGNORECASE)
        
        if len(path) > 100:
            path = path[:100] + '...'
        
        return path
    
    def _should_track_combination(self, user_hash, normalized_path):
        combination_key = f"{user_hash}:{normalized_path}"
        
        if combination_key in self.user_path_combinations:
            return True, combination_key
        
        if len(self.user_path_combinations) >= self.max_unique_combinations:
            self.cardinality_limit_hits.labels(limit_type='combinations').inc()
            return False, None
        
        if len(self.user_hashes) >= self.max_users:
            if user_hash not in [v for v in self.user_hashes.values()]:
                self.cardinality_limit_hits.labels(limit_type='users').inc()
                return False, None
        
        if len(self.path_patterns) >= self.max_paths:
            if normalized_path not in self.path_patterns:
                self.cardinality_limit_hits.labels(limit_type='paths').inc()
                return False, None
        
        return True, combination_key
    
    def record_request(self, user_id, session_id, path, status_code=200, duration=None):
        with self.lock:
            user_hash = self._hash_user_id(user_id)
            normalized_path = self._normalize_path(path)
            
            should_track, combination_key = self._should_track_combination(user_hash, normalized_path)
            
            if should_track and combination_key:
                if combination_key not in self.user_path_combinations:
                    self.user_path_combinations[combination_key] = {
                        'user_hash': user_hash,
                        'path': normalized_path,
                        'count': 0,
                        'total_duration': 0.0,
                        'status_codes': defaultdict(int)
                    }
                    self.path_patterns[normalized_path] = True
                
                self.user_path_combinations[combination_key]['count'] += 1
                self.user_path_combinations[combination_key]['status_codes'][status_code] += 1
                
                if duration is not None:
                    self.user_path_combinations[combination_key]['total_duration'] += duration
            
            self.total_requests.labels(status=str(status_code)).inc()
            
            if duration is not None:
                self.request_duration.labels(status=str(status_code)).observe(duration)
            
            if session_id:
                self.session_tracker[session_id] = True
                self.session_last_seen[session_id] = time.time()
            
            self.unique_combinations_gauge.set(len(self.user_path_combinations))
    
    def update_active_sessions(self, timeout=300):
        with self.lock:
            current_time = time.time()
            expired_sessions = [
                sid for sid, last_seen in self.session_last_seen.items()
                if current_time - last_seen > timeout
            ]
            
            for sid in expired_sessions:
                del self.session_tracker[sid]
                del self.session_last_seen[sid]
            
            self.active_sessions.set(len(self.session_tracker))
    
    def get_user_path_metrics(self):
        with self.lock:
            metrics = []
            for key, data in self.user_path_combinations.items():
                metrics.append({
                    'user_hash': data['user_hash'],
                    'path': data['path'],
                    'count': data['count'],
                    'avg_duration': data['total_duration'] / data['count'] if data['count'] > 0 else 0,
                    'status_codes': dict(data['status_codes'])
                })
            return metrics
    
    def cleanup_old_combinations(self, min_requests=5):
        with self.lock:
            keys_to_remove = [
                key for key, data in self.user_path_combinations.items()
                if data['count'] < min_requests
            ]
            
            for key in keys_to_remove:
                del self.user_path_combinations[key]
            
            self.unique_combinations_gauge.set(len(self.user_path_combinations))
            
            return len(keys_to_remove)


class UserPathMetricsCollector:
    def __init__(self, metrics_tracker):
        self.metrics_tracker = metrics_tracker
    
    def collect(self):
        user_path_requests = CounterMetricFamily(
            'http_user_path_requests_total',
            'Total requests per user-path combination',
            labels=['user_hash', 'path', 'status']
        )
        
        user_path_duration = GaugeMetricFamily(
            'http_user_path_avg_duration_seconds',
            'Average request duration per user-path combination',
            labels=['user_hash', 'path']
        )
        
        metrics = self.metrics_tracker.get_user_path_metrics()
        
        for metric in metrics:
            for status_code, count in metric['status_codes'].items():
                user_path_requests.add_metric(
                    [metric['user_hash'], metric['path'], str(status_code)],
                    count
                )
            
            user_path_duration.add_metric(
                [metric['user_hash'], metric['path']],
                metric['avg_duration']
            )
        
        yield user_path_requests
        yield user_path_duration


def create_metrics_app(max_combinations=1000, max_paths=500, max_users=500):
    metrics_tracker = CardinalityLimitedMetrics(
        max_unique_combinations=max_combinations,
        max_paths=max_paths,
        max_users=max_users
    )
    
    collector = UserPathMetricsCollector(metrics_tracker)
    REGISTRY.register(collector)
    
    return metrics_tracker


